mapper.select:
SELECT
    t.id, t.ticket_no, t.title, t.status, t.priority,
    t.category_id, c.name AS category_name,
    t.reporter_id, t.reporter_name,
    t.assignee_id, t.assignee_name,
    t.dept_id, t.sla_deadline, t.sla_breached,
    t.comment_count, t.attachment_count,
    t.tags, t.source,
    t.create_time, t.update_time
FROM ticket t
LEFT JOIN ticket_category c ON t.category_id = c.id AND c.deleted = 0
WHERE t.deleted = 0

    AND t.status = #{query.status}


    AND t.priority = #{query.priority}


    AND t.category_id = #{query.categoryId}


    AND t.assignee_id = #{query.assigneeId}


    AND t.reporter_id = #{query.reporterId}


    AND t.dept_id = #{query.deptId}


    AND (t.title LIKE CONCAT('%', #{query.keyword}, '%')
         OR t.ticket_no LIKE CONCAT('%', #{query.keyword}, '%'))


    AND t.create_time >= #{query.startDate}


    AND t.create_time <= #{query.endDate}

ORDER BY
    CASE t.priority WHEN 1 THEN 0 WHEN 2 THEN 1 WHEN 3 THEN 2 WHEN 4 THEN 3 END ASC,
    t.create_time DESC
